class SecureObjectInputStream extends ObjectInputStream {
    private final Set<String> allowedClasses;

    public SecureObjectInputStream(InputStream in, Set<String> allowedClasses) throws IOException {
        super(in);
        this.allowedClasses = allowedClasses;
    }

    @Override
    protected Class<?> resolveClass(ObjectStreamClass desc) throws IOException, ClassNotFoundException {
        String className = desc.getName();
        
        if (!isAllowedClass(className)) {
            throw new InvalidClassException("Unauthorized deserialization attempt for class: " + className);
        }
        
        return super.resolveClass(desc);
    }

    private boolean isAllowedClass(String className) {
        if (allowedClasses.contains(className)) {
            return true;
        }
        
        if (className.startsWith("java.lang.") || 
            className.startsWith("java.util.") ||
            className.equals("[Ljava.lang.String;") ||
            className.equals("[Ljava.lang.Object;") ||
            className.startsWith("[L") && isAllowedClass(className.substring(2, className.length() - 1))) {
            return true;
        }
        
        return false;
    }
}

